import json

def load_tasks():
    try:
        with open('tasks.json') as f:
            return json.load(f)
    except FileNotFoundError:
        return []

def save_tasks(tasks):
    with open('tasks.json', 'w') as f:
        json.dump(tasks, f)

def list_tasks(tasks):
    if not tasks:
        print('No tasks yet.')
        return
    for i, task in enumerate(tasks, 1):
        print(f'{i}. {task}')

def add_task(tasks, name):
    tasks.append(name)
    print(f'Added: {name}')

